# detect_smurfing function
def detect_smurfing(transactions):
    smurfing_activations = 0
    for transaction in transactions:
        if transaction < 8000:
            smurfing_activations = 0
        elif 8000 <= transaction <= 9999:
            smurfing_activations += 1
            if smurfing_activations == 3:
                return True
        else:
            smurfing_activations = 0
    return False
